-- Repartidor de misiones
lang["#MISSION_GIVER_CROWMAN"] = "Joe el Cuervo"
lang["#MISSION_GIVER_CROWMAN_SUBTITLE"] = "Sal de la tierra, insolación del cerebro."
lang["#MISSION_GIVER_CROWMAN_GREET_0"] = "¡Tú, mocoso! ¡Ven aquí! ¡Los cuervos están otra vez, planeando robar mi maíz! ¡Los oigo venir ahora mismo!"

-- Misiones
lang["#MISSION_CROWMAN_SINGLESHOTGUN"] = "Todos Empiezan en Algún Lado"
lang["#MISSION_CROWMAN_SINGLESHOTGUN_DESC"] = "¡Tú, mocoso! ¿Vienes a robarme el maíz? ¿No? Debes haberte escapado del pueblo mientras tus padres estaban distraídos. Apuesto a que un mocoso bizco como tú no podría darle a un cuervo aunque se le posara en la nariz. ¡Un mocoso como tú necesita que le enseñen los principios! ¡Consíguete un cuervo usando una vieja Escopeta de un Solo Cañón, Y NADA MÁS! ¡LO SABRÉ! Los parientes de Nimrod me enseñaron a rastrear a un mentiroso por el olfato."
lang["#MISSION_CROWMAN_SINGLESHOTGUN_HINT"] = "Adquiere una Escopeta de un Solo Cañón, mediante trueque, saqueo u otra cosa...\n\nLos cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ¡Asegúrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_SINGLESHOTGUN_COMPLETE"] = "Supongo que no eres tan estúpido como pareces. ¡Pero no te creas superior! ¡Maté a mi primer cuervo a los dos años!"

lang["#MISSION_CROWMAN_357"] = "Martillo Emplumado"
lang["#MISSION_CROWMAN_357_DESC"] = "¡Tú, mocoso! Tengo un nuevo desafío para ti. Esta vez, quiero que mates un cuervo usando un Revólver .357 o un Repetidor de Vaquero, ¡Y NADA MÁS! ¡LO SABRÉ!"
lang["#MISSION_CROWMAN_357_HINT"] = "Adquiere un Revólver .357 o un Repetidor de Vaquero, mediante trueque, saqueo u otra cosa...\n\nLos cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ¡Asegúrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_357_COMPLETE"] = "¿Por fin terminaste? ¡Te tomó bastante tiempo!"
lang["#MISSION_CROWMAN_357_WEP"] = "Revólver .357 o Repetidor de Vaquero"

lang["#MISSION_CROWMAN_SERVICERIFLE"] = "Graznido de Metal Completo"
lang["#MISSION_CROWMAN_SERVICERIFLE_DESC"] = "¡Tú, mocoso! Tengo un nuevo desafío para ti. Esta vez, quiero que mates un cuervo usando uno de esos rifles de los chicos de la RNC, ¡Y NADA MÁS! ¡LO SABRÉ!"
