lang["#MISSION_CROWMAN_CROWBAR"] = "No pretendo entrometerme..."
lang["#MISSION_CROWMAN_CROWBAR_DESC"] = "¡Tú, mocoso! ¡Esta vez te tengo! ¡Te tengo calado! ¡NO HAY MANERA de que superes este desafío! Quiero que mates un cuervo. Solo uno más. Y lo harás usando una palanca. ¡Y NADA MÁS! ¡LO SABRÉ!"
lang["#MISSION_CROWMAN_CROWBAR_HINT"] = "Adquiere una Palanca, mediante trueque, saqueo u otra cosa...\n\nLos cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores."
lang["#MISSION_CROWMAN_CROWBAR_COMPLETE"] = "Está bien, ganas. Puedes quedarte con esto. Y con esta escopeta. Iba a ser para mi hijo cuando alcanzara la mayoría de edad. Antes de... que los cuervos se lo llevaran..."

-- Desafío de cantidad

lang["#MISSION_CROWMAN_X10"] = "Control de Plagas"
lang["#MISSION_CROWMAN_X10_DESC"] = "¡Tú, mocoso! ¡Los has visto, ¿verdad?! ¡Planeando, aleteando, lanzando maldiciones en su lengua picuda, y lo peor de todo! ¡ROBANDO MI MAÍZ! Los cuervos han vuelto, y se han enterado de lo que hiciste. Saben que mataste a uno de los suyos, sin provocación y sin aliento de nadie más. ¡Ahora están robando mi maíz en venganza! ¡Tú causaste esto, ahora lo arreglas!"
lang["#MISSION_CROWMAN_X10_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ¡Asegúrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X10_COMPLETE"] = "¿Los atrapaste a todos? Te tomó bastante tiempo. ¡Yo podría haberlo hecho en la mitad de tiempo, si no estuviera ocupado vigilando mi maíz!"

lang["#MISSION_CROWMAN_X25"] = "Depredación"
lang["#MISSION_CROWMAN_X25_DESC"] = "¡Tú, mocoso! Apuesto a que te sientes muy orgulloso por el trabajo que hiciste con los cuervos antes, ¿eh? ¡PUES NO DEBERÍAS! ¡Han vuelto! Lo vi con mis propios ojos, un cuervo bajó volando y le arrebató la comida de las manos a Isaac. Lo más divertido que he visto en toda la semana. ¡Pero todavía tienes un lío que limpiar! ¡Sal ahí y acaba con el resto!"
lang["#MISSION_CROWMAN_X25_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ¡Asegúrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X25_COMPLETE"] = "¿Por fin terminaste? Ya veremos. Esos cuervos son listos. ¡Pero no más que yo! ¡Conozco sus trucos!"

lang["#MISSION_CROWMAN_X50"] = "ConCAWflicto Abierto"
lang["#MISSION_CROWMAN_X50_DESC"] = "¡Tú, mocoso! Pensé que te dije que te encargaras del problema de los cuervos. ¿El que causaste en primer lugar? ¿Entonces por qué me desperté esta mañana solo para encontrar una bandada entera de cuervos, sentados en mi granero, mirándome con sus pequeños ojos de cuentas? ¡Están construyendo un ejército, NO, UNA FUERZA AÉREA! ¡Tienes que diezmarlos antes de que sea demasiado tarde!"
lang["#MISSION_CROWMAN_X50_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ¡Asegúrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X50_COMPLETE"] = "¿Terminaste? ¡Bien! La mayoría de la gente no habría necesitado tres intentos para hacerlo, pero la mayoría de la gente no es como tú."

lang["#MISSION_CROWMAN_X100"] = "Asesinato, a escala macabra"
lang["#MISSION_CROWMAN_X100_DESC"] = "No puedo casi creerlo. Aquí estaba yo, seguro de que la última vez que saliste a mi campo, me dijiste que habías resuelto el problema de los cuervos.\n¿El que están concentrando sus fuerzas en masa? ¿EL PROBLEMA QUE CAUSASTE EN PRIMER LUGAR! ¿Entonces por qué cuando ese tal Ike, ese excusa de barman, vino a recoger su último celemín de mi maíz, empezó a contarme algo que escuchó de uno de sus parroquianos? Dijo que el chico llegó tambaleándose desde las ruinas de Fallon, y no paraba de hablar de una flota entera de pájaros negros reunidos al otro lado de las colinas, al oeste. ¡Ve a ello, y hazlo bien esta vez!"
lang["#MISSION_CROWMAN_X100_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ¡Asegúrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X100_COMPLETE"] = "¡Mocoso! No descorches el licor de maíz todavía. Llámalo reconocimiento de patrones, pero creo que esto es la calma antes de la tormenta..."

lang["#MISSION_CROWMAN_X200"] = "Nunca Más"
lang["#MISSION_CROWMAN_X200_DESC"] = "¡Tú, mocoso! Nuestros peores temores se han hecho realidad. Tu completo fracaso en sofocar una simple rencilla con los cuervos ha degenerado en una guerra total entre cuervos y humanos. Envié a Andrew a explorar las líneas enemigas hace 30 minutos y no he tenido noticias suyas desde entonces, temo que ya esté muerto. Reúne toda la munición, estimulantes y drogas que puedas llevar en tus brazos. Si ambos sobrevivimos a esto, ¡puede que te perdone por haber creado este problema en primer lugar!"
lang["#MISSION_CROWMAN_X200_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ¡Asegúrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X200_COMPLETE"] = "¿Se... se acabó? ¿Ganamos? ¡Lo hicimos! ¡A pesar de todos tus fracasos, los rechazamos!"

RELOADSCHEMA = true
